--CREATE DATABASE lab3_ecommerce_db;

CREATE TABLE IF NOT EXISTS public.brand
(
    brand_id integer NOT NULL,
    brand_name character varying(100) COLLATE pg_catalog."default" NOT NULL,
    country character varying(50) COLLATE pg_catalog."default" NOT NULL,
    create_at timestamp without time zone NOT NULL,
    CONSTRAINT brand_pkey PRIMARY KEY (brand_id)
);


CREATE TABLE public.category (
    category_id integer NOT NULL,
    category_name character varying(100) NOT NULL,
    parent_category_id integer,
    level smallint NOT NULL,
    created_at timestamp without time zone NOT NULL
);


CREATE TABLE public.seller (
    seller_id integer NOT NULL,
    seller_name character varying(150) NOT NULL,
    join_date date NOT NULL,
    seller_type character varying(50) NOT NULL,
    rating numeric(2,1) NOT NULL,
    country character varying(50) NOT NULL
);


CREATE TABLE public.product (
    product_id integer NOT NULL,
    product_name character varying(200) NOT NULL,
    category_id integer,
    brand_id integer,
    seller_id integer,
    price numeric(12,2) NOT NULL,
    discount_price numeric(12,2) NOT NULL,
    stock_qty integer NOT NULL,
    rating double precision NOT NULL,
    created_at timestamp without time zone NOT NULL,
    is_active boolean NOT NULL
);

